nodes.notes:
Receives a policy change proposal. Example POST body:
{
  "proposal": "Enable auto-refunds under $100",
  "current_state": {
    "trust_score": 75,
    "refund_rate": 12,
    "abuse_rate": 3
  }
}

parameters.functionCode:
// ─── Merge all 3 simulation profiles and make a deployment decision ───
// The Simulate node already outputs: simulation.viable, simulation.finalViability,
// simulation.collapsed, insights.stateDeltas, insights.nativeNarrative, etc.
// No intermediate "Analyze" node needed.

const profiles = {};
for (const item of items) {
  const sim = item.json.simulation;
  const insights = item.json.insights || {};
  profiles[sim.profile] = {
    viable: sim.viable,
    viability: sim.finalViability,
    collapsed: sim.collapsed,
    collapseStep: sim.collapseStep || null,
    collapseRule: sim.collapseRule || null,
    steps: sim.steps,
    stateDeltas: insights.stateDeltas || {},
    nativeNarrative: insights.nativeNarrative || '',
    contextNarrative: insights.contextNarrative || '',
    totalRulesFired: insights.totalRulesFired || 0,
    totalRulesEvaluated: insights.totalRulesEvaluated || 0,
    rulesNeverTriggered: insights.rulesNeverTriggered || [],
    initialState: sim.initialState,
    finalState: sim.finalState,
    stepDetails: sim.stepDetails || []
  };
}

const best = profiles.best_case || {};
const expected = profiles.expected || {};
const worst = profiles.worst_case || {};

// ─── Decision Logic ───
const viabilities = [best.viability, expected.viability, worst.viability];
const anyCritical = viabilities.includes('CRITICAL') || viabilities.includes('MODEL_COLLAPSES');
const anyCollapsed = best.collapsed || expected.collapsed || worst.collapsed;
const allHealthy = viabilities.every(v => v === 'THRIVING' || v === 'STABLE');
const expectedOk = expected.viability === 'THRIVING' || expected.viability === 'STABLE';

let decision, recommendation;
if (allHealthy) {
  decision = 'APPROVE';
  recommendation = 'All scenarios remain healthy through 10 steps. Safe to enable auto-refunds.';
} else if (expectedOk && !anyCollapsed) {
  decision = 'APPROVE_WITH_GUARDRAILS';
  recommendation = 'Expected case is stable, but worst case shows degradation. Enable with monitoring and abuse detection guardrails.';
} else if (anyCritical || anyCollapsed) {
  decision = 'BLOCK';
  recommendation = 'System reaches CRITICAL or collapses under realistic conditions. Do NOT enable auto-refunds without fundamental changes.';
} else {
  decision = 'REVIEW';
  recommendation = 'Mixed results — requires human review of the behavioral trajectories before proceeding.';
}

// ─── Find dominant rules across all profiles ───
const allRules = {};
for (const [name, profile] of Object.entries(profiles)) {
  for (const step of (profile.stepDetails || [])) {
    for (const rule of (step.rulesTriggered || [])) {
      const key = rule.ruleId;
      if (!allRules[key]) allRules[key] = { ruleId: key, label: rule.label, totalFires: 0, profiles: [] };
      allRules[key].totalFires++;
      if (!allRules[key].profiles.includes(name)) allRules[key].profiles.push(name);
    }
  }
}
const topThreats = Object.values(allRules).sort((a, b) => b.totalFires - a.totalFires).slice(0, 3);

// ─── Build the report ───
const lines = [];
lines.push('===== BEHAVIORAL SIMULATION REPORT =====');
lines.push('');
lines.push('Policy: Enable AI auto-refunds under $100');
lines.push('Simulation: 10 steps across 3 assumption profiles');
lines.push('');

// Include the governance engine's native narrative for each profile
lines.push('--- NARRATIVES (from governance engine) ---');
for (const [name, profile] of Object.entries(profiles)) {
  lines.push(`\n  [${name.replace('_', ' ').toUpperCase()}]`);
  if (profile.nativeNarrative) {
    lines.push('  ' + profile.nativeNarrative.split('\n').join('\n  '));
  }
}
lines.push('');

lines.push('--- OUTCOMES ---');
for (const [name, profile] of Object.entries(profiles)) {
  const label = name.replace('_', ' ').toUpperCase();
  const v = profile.viability || 'UNKNOWN';
  const collapsed = profile.collapsed ? ' [COLLAPSED]' : '';
  lines.push(`  ${label}: ${v}${collapsed}`);

  // State deltas from Simulate node
  const deltas = profile.stateDeltas || {};
  for (const [key, delta] of Object.entries(deltas)) {
    if (delta && delta.from !== undefined && delta.to !== undefined) {
      const from = typeof delta.from === 'number' ? Math.round(delta.from * 10) / 10 : delta.from;
      const to = typeof delta.to === 'number' ? Math.round(delta.to * 10) / 10 : delta.to;
      lines.push(`    ${key}: ${from} -> ${to}`);
    }
  }
  lines.push('');
}

if (topThreats.length > 0) {
  lines.push('--- ROOT CAUSE ANALYSIS ---');
  for (const threat of topThreats) {
    lines.push(`  ${threat.label || threat.ruleId}`);
    lines.push(`    Fired ${threat.totalFires}x across profiles: ${threat.profiles.join(', ')}`);
  }
  lines.push('');
}

lines.push('--- DECISION ---');
lines.push(`  ${decision}`);
lines.push(`  ${recommendation}`);

const report = lines.join('\n');

return [{
  json: {
    decision,
    recommendation,
    report,
    profiles: {
      best_case: { viability: best.viability, viable: best.viable, collapsed: best.collapsed, stateDeltas: best.stateDeltas },
      expected: { viability: expected.viability, viable: expected.viable, collapsed: expected.collapsed, stateDeltas: expected.stateDeltas },
      worst_case: { viability: worst.viability, viable: worst.viable, collapsed: worst.collapsed, stateDeltas: worst.stateDeltas }
    },
    topThreats,
    narratives: {
      best_case: best.contextNarrative,
      expected: expected.contextNarrative,
      worst_case: worst.contextNarrative
    }
  }
}];
